task("fund", "Sends 1 FIL to bounty contract.")
    .addParam("contract", "The address of the DealRewarder contract")
    .setAction(async (taskArgs, hre: HardhatRuntimeEnvironment) => {
        const contractAddr = taskArgs.contract
        const networkId = hre.network.name
        console.log("Sending 1 FIL to DealRewarder contract on network", networkId)

        //create a new wallet instance
        const [wallet] = await hre.ethers.getSigners()

        //create a FilecoinMarketConsumer contract factory
        const DealRewarder = await hre.ethers.getContractFactory("DealRewarder", wallet)
        //create a DealRewarder contract instance
        //this is what you will call to interact with the deployed contract
        const dealRewarder = DealRewarder.attach(contractAddr) as DealRewarder

        //send a transaction to call fund() method
        const transaction = await dealRewarder.fund(0, {
            value: parseEther("1"),
        })
        await transaction.wait()
        console.log("Complete!")
    })

abstract class ScarbWrapper {
    private static instance: ScarbWrapper;

    static getInstance(cliArgs: TaskArguments, hre: HardhatRuntimeEnvironment): ScarbWrapper {
        if (this.instance) {
            return this.instance;
        } else if (cliArgs.scarbCommand) {
            this.instance = new CustomScarbWrapper(cliArgs.scarbCommand);
        } else if (hre.config.starknet.scarbCommand) {
            this.instance = new CustomScarbWrapper(hre.config.starknet.scarbCommand);
        } else {
            this.instance = new DockerizedScarbWrapper(
                hre.config.starknet.dockerizedVersion,
                hre.config.paths.root
            );
        }
        return this.instance;
    }

    public abstract build(packageConfigPath: string, artifactDirPath: string): ProcessResult;
}

subtask(SUBTASK_PREPARE_PACKAGE_TYPECHAIN).setAction(async function (_taskArgs: TaskArguments, { config }) {
  const pathToBindings: string = join(config.paths.root, config.typechain.outDir);
  if (!fsExtra.existsSync(pathToBindings)) {
    throw new HardhatPluginError(PLUGIN_NAME, "Please generate the TypeChain bindings before running this plugin");
  }

  // TypeChain generates some files that are shared across all bindings.
  const excludedFiles: string[] = ["common"];

  // Delete all bindings that have not been allowlisted.
  for await (const pathToBinding of getFilesRecursively(pathToBindings)) {
    const fileName: string = basename(pathToBinding, extname(pathToBinding));
    if (excludedFiles.includes(fileName)) {
      continue;
    }
    if (!config.packager.contracts.includes(fileName)) {
      await fsExtra.remove(pathToBinding);
    }
  }

  // Delete any remaining empty directories.
  for await (const pathToEmptyBindingDirectory of getEmptyDirectoriesRecursively(pathToBindings)) {
    await fsExtra.remove(pathToEmptyBindingDirectory);
  }
});

subtask(SUBTASK_PREPARE_PACKAGE_TYPECHAIN_FACTORIES).setAction(async function (_taskArgs: TaskArguments, { config }) {
  const pathToBindingsFactories: string = join(config.paths.root, config.typechain.outDir, "factories");
  if (!fsExtra.existsSync(pathToBindingsFactories)) {
    throw new HardhatPluginError(
      PLUGIN_NAME,
      "Please generate the TypeChain bindings factories before running this plugin",
    );
  }

  for await (const pathToBindingFactory of getFilesRecursively(pathToBindingsFactories)) {
    const contract: string = parse(pathToBindingFactory).name.replace("__factory", "");
    if (!config.packager.contracts.includes(contract)) {
      await fsExtra.remove(pathToBindingFactory);
    }
  }

  // Delete any remaining empty directories.
  for await (const pathToEmptyBindingFactoryDirectory of getEmptyDirectoriesRecursively(pathToBindingsFactories)) {
    await fsExtra.remove(pathToEmptyBindingFactoryDirectory);
  }
});

export default async (): Promise<Partial<ConfigHooks>> => {
	const handlers: Partial<ConfigHooks> = {
		validateUserConfig: validateTypechainUserConfig,
		resolveUserConfig: async (userConfig, resolveConfigurationVariable, next) => {
			const resolvedConfig = await next(userConfig, resolveConfigurationVariable);

			const solidity: SolidityConfig = structuredClone(resolvedConfig.solidity);
			const profiles: Record<string, SolidityBuildProfileConfig> = solidity.profiles;
			for (const profileName of Object.keys(profiles)) {
				const profile: SolidityBuildProfileConfig = profiles[profileName];
				const compilers = profile.compilers;
				for (const compiler of compilers) {
					const settings = compiler.settings;
					setupExtraSolcSettings(settings);
				}
			}

			return {
				...resolvedConfig,
				solidity,
				generateTypedArtifacts: getConfig(userConfig.generateTypedArtifacts),
			};
		},
	};

	return handlers;
};

interface EdrNetworkConfig {
  type: "edr-simulated";
  accounts: EdrNetworkAccountsConfig;
  chainId: number;
  chainType?: ChainType;
  from?: string;
  gas: GasConfig;
  gasMultiplier: number;
  gasPrice: GasConfig;

  // EDR network specific
  allowBlocksWithSameTimestamp: boolean;
  allowUnlimitedContractSize?: boolean;
  blockGasLimit?: bigint | false;
  coinbase: Uint8Array;
  forking?: EdrNetworkForkingConfig;
  hardfork: string;
  initialBaseFeePerGas?: bigint;
  initialDate: string | Date;
  loggingEnabled: boolean;
  minGasPrice: bigint;
  mining: EdrNetworkMiningConfig;
  networkId: number;
  throwOnCallFailures: boolean;
  throwOnTransactionFailures: boolean;
  transactionGasCap?: bigint | false;
}
